@Service
class ElasticsearchIndexService {
    private static final String PRODUCTS_INDEX = "products";
    private static final String SEARCH_QUERIES_INDEX = "search_queries";

    private final RestHighLevelClient client;

    ElasticsearchIndexService(RestHighLevelClient client) {
        this.client = client;
    }

    public void createProductsIndexIfNotExists() throws IOException {
        GetIndexRequest getIndexRequest = new GetIndexRequest(PRODUCTS_INDEX);
        if (!client.indices().exists(getIndexRequest, RequestOptions.DEFAULT)) {
            CreateIndexRequest request = new CreateIndexRequest(PRODUCTS_INDEX);
            request.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 1));
            request.mapping("{\n" +
                    "  \"properties\": {\n" +
                    "    \"name\": {\"type\": \"text\", \"analyzer\": \"standard\", \"fields\": {\"keyword\": {\"type\": \"keyword\"}}},\n" +
                    "    \"description\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                    "    \"brand\": {\"type\": \"keyword\"},\n" +
                    "    \"category\": {\"type\": \"keyword\"},\n" +
                    "    \"tags\": {\"type\": \"keyword\"},\n" +
                    "    \"price\": {\"type\": \"double\"},\n" +
                    "    \"quantity\": {\"type\": \"integer\"},\n" +
                    "    \"available\": {\"type\": \"boolean\"},\n" +
                    "    \"rating\": {\"type\": \"double\"},\n" +
                    "    \"createdAt\": {\"type\": \"date\"}\n" +
                    "  }\n" +
                    "}", XContentType.JSON);
            client.indices().create(request, RequestOptions.DEFAULT);
        }
    }

    public void createSearchQueriesIndexIfNotExists() throws IOException {
        GetIndexRequest getIndexRequest = new GetIndexRequest(SEARCH_QUERIES_INDEX);
        if (!client.indices().exists(getIndexRequest, RequestOptions.DEFAULT)) {
            CreateIndexRequest request = new CreateIndexRequest(SEARCH_QUERIES_INDEX);
            request.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 1));
            request.mapping("{\n" +
                    "  \"properties\": {\n" +
                    "    \"query\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                    "    \"filters\": {\"type\": \"object\", \"enabled\": true},\n" +
                    "    \"searchedAt\": {\"type\": \"date\"},\n" +
                    "    \"resultsCount\": {\"type\": \"long\"}\n" +
                    "  }\n" +
                    "}", XContentType.JSON);
            client.indices().create(request, RequestOptions.DEFAULT);
        }
    }

    public String getProductsIndex() {
        return PRODUCTS_INDEX;
    }

    public String getSearchQueriesIndex() {
        return SEARCH_QUERIES_INDEX;
    }

    public void deleteIndex(String index) throws IOException {
        client.indices().delete(new DeleteIndexRequest(index), RequestOptions.DEFAULT);
    }
}

@Service
class ProductSearchService {
    private final RestHighLevelClient client;
    private final ElasticsearchIndexService indexService;

    ProductSearchService(RestHighLevelClient client, ElasticsearchIndexService indexService) {
        this.client = client;
        this.indexService = indexService;
    }

    public void indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isBlank()) {
            product.setId(UUID.randomUUID().toString());
        }
        if (product.getCreatedAt() == null) {
            product.setCreatedAt(Instant.now());
        }
        IndexRequest request = new IndexRequest(indexService.getProductsIndex())
                .id(product.getId())
                .source(toProductMap(product));
        client.index(request, RequestOptions.DEFAULT);
    }

    public void indexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        for (Product product : products) {
            if (product.getId() == null || product.getId().isBlank()) {
                product.setId(UUID.randomUUID().toString());
            }
            if (product.getCreatedAt() == null) {
                product.setCreatedAt(Instant.now());
            }
            bulkRequest.add(new IndexRequest(indexService.getProductsIndex())
                    .id(product.getId())
                    .source(toProductMap(product)));
        }
        BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        if (response.hasFailures()) {
            throw new IOException("Bulk indexing failed: " + response.buildFailureMessage());
        }
    }

    public ProductSearchResponse searchProducts(ProductSearchRequest request) throws IOException {
        SearchRequest searchRequest = new SearchRequest(indexService.getProductsIndex());
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (request.getQuery() != null && !request.getQuery().isBlank()) {
            MultiMatchQueryBuilder textQuery = QueryBuilders.multiMatchQuery(request.getQuery(), "name^3", "description^2", "brand", "category")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS);
            boolQuery.must(textQuery);
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (request.getCategory() != null && !request.getCategory().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("category", request.getCategory()));
        }
        if (request.getBrand() != null && !request.getBrand().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("brand", request.getBrand()));
        }
        if (request.getTags() != null && !request.getTags().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("tags", request.getTags()));
        }
        if (request.getAvailable() != null) {
            boolQuery.filter(QueryBuilders.termQuery("available", request.getAvailable()));
        }
        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (request.getMinPrice() != null) {
                rangeQuery.gte(request.getMinPrice());
            }
            if (request.getMaxPrice() != null) {
                rangeQuery.lte(request.getMaxPrice());
            }
            boolQuery.filter(rangeQuery);
        }

        sourceBuilder.query(boolQuery);
        sourceBuilder.from(Math.max(request.getPage(), 0) * Math.max(request.getSize(), 1));
        sourceBuilder.size(Math.max(request.getSize(), 1));

        TermsAggregationBuilder categoryFacet = AggregationBuilders.terms("categoryFacet").field("category").size(20);
        TermsAggregationBuilder brandFacet = AggregationBuilders.terms("brandFacet").field("brand").size(20);
        TermsAggregationBuilder tagsFacet = AggregationBuilders.terms("tagsFacet").field("tags").size(30);

        sourceBuilder.aggregation(categoryFacet);
        sourceBuilder.aggregation(brandFacet);
        sourceBuilder.aggregation(tagsFacet);

        searchRequest.source(sourceBuilder);

        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> products = Arrays.stream(response.getHits().getHits())
                .map(this::fromSearchHit)
                .collect(Collectors.toList());

        Map<String, List<FacetBucket>> facets = new HashMap<>();
        facets.put("category", parseTermsFacet((ParsedStringTerms) response.getAggregations().get("categoryFacet")));
        facets.put("brand", parseTermsFacet((ParsedStringTerms) response.getAggregations().get("brandFacet")));
        facets.put("tags", parseTermsFacet((ParsedStringTerms) response.getAggregations().get("tagsFacet")));

        logSearchQuery(request, response.getHits().getTotalHits().value);

        return new ProductSearchResponse(products, response.getHits().getTotalHits().value, facets);
    }

    public void logSearchQuery(ProductSearchRequest request, long resultsCount) throws IOException {
        SearchQueryLog log = new SearchQueryLog(
                UUID.randomUUID().toString(),
                request.getQuery(),
                buildFiltersMap(request),
                Instant.now(),
                resultsCount
        );
        IndexRequest indexRequest = new IndexRequest(indexService.getSearchQueriesIndex())
                .id(log.getId())
                .source(toSearchLogMap(log));
        client.index(indexRequest, RequestOptions.DEFAULT);
    }

    private Map<String, Object> toProductMap(Product product) {
        Map<String, Object> map = new HashMap<>();
        map.put("name", product.getName());
        map.put("description", product.getDescription());
        map.put("brand", product.getBrand());
        map.put("category", product.getCategory());
        map.put("tags", product.getTags());
        map.put("price", product.getPrice());
        map.put("quantity", product.getQuantity());
        map.put("available", product.getAvailable());
        map.put("rating", product.getRating());
        map.put("createdAt", product.getCreatedAt() != null ? product.getCreatedAt().toString() : null);
        return map;
    }

    private Map<String, Object> toSearchLogMap(SearchQueryLog log) {
        Map<String, Object> map = new HashMap<>();
        map.put("query", log.getQuery());
        map.put("filters", log.getFilters());
        map.put("searchedAt", log.getSearchedAt() != null ? log.getSearchedAt().toString() : null);
        map.put("resultsCount", log.getResultsCount());
        return map;
    }

    private Product fromSearchHit(SearchHit hit) {
        Map<String, Object> source = hit.getSourceAsMap();
        Product product = new Product();
        product.setId(hit.getId());
        product.setName((String) source.get("name"));
        product.setDescription((String) source.get("description"));
        product.setBrand((String) source.get("brand"));
        product.setCategory((String) source.get("category"));
        Object tags = source.get("tags");
        if (tags instanceof List) {
            product.setTags(((List<?>) tags).stream().map(String::valueOf).collect(Collectors.toList()));
        }
        if (source.get("price") != null) {
            product.setPrice(Double.valueOf(source.get("price").toString()));
        }
        if (source.get("quantity") != null) {
            product.setQuantity(Integer.valueOf(source.get("quantity").toString()));
        }
        if (source.get("available") != null) {
            product.setAvailable(Boolean.valueOf(source.get("available").toString()));
        }
        if (source.get("rating") != null) {
            product.setRating(Double.valueOf(source.get("rating").toString()));
        }
        if (source.get("createdAt") != null) {
            product.setCreatedAt(Instant.parse(source.get("createdAt").toString()));
        }
        return product;
    }

    private List<FacetBucket> parseTermsFacet(ParsedStringTerms terms) {
        if (terms == null) {
            return Collections.emptyList();
        }
        return terms.getBuckets().stream()
                .map(bucket -> new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()))
                .collect(Collectors.toList());
    }

    private Map<String, Object> buildFiltersMap(ProductSearchRequest request) {
        Map<String, Object> filters = new HashMap<>();
        filters.put("category", request.getCategory());
        filters.put("brand", request.getBrand());
        filters.put("tags", request.getTags());
        filters.put("minPrice", request.getMinPrice());
        filters.put("maxPrice", request.getMaxPrice());
        filters.put("available", request.getAvailable());
        filters.put("page", request.getPage());
        filters.put("size", request.getSize());
        return filters;
    }
}

@RestController
@RequestMapping("/api/products")
class ProductController {
    private final ProductSearchService productSearchService;

    ProductController(ProductSearchService productSearchService) {
        this.productSearchService = productSearchService;
    }

    @PostMapping
    public ResponseEntity<Map<String, String>> indexProduct(@RequestBody Product product) throws IOException {
        productSearchService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED).body(Map.of("message", "Product indexed", "id", product.getId()));
    }

    @PostMapping("/bulk")
    public ResponseEntity<Map<String, Object>> indexProducts(@RequestBody List<Product> products) throws IOException {
        productSearchService.indexProducts(products);
        return ResponseEntity.status(HttpStatus.CREATED).body(Map.of("message", "Products indexed", "count", products.size()));
    }

    @PostMapping("/search")
    public ResponseEntity<ProductSearchResponse> search(@RequestBody ProductSearchRequest request) throws IOException {
        return ResponseEntity.ok(productSearchService.searchProducts(request));
    }
}

